#include <iostream>
#include <fstream>
#include <string>
#include <algorithm>
#include <regex>

using namespace std;

// Function to count occurrences of a word in a single line with word boundary checks
int countOccurrencesInLine(const string& line, const string& word) {
    regex wordRegex("\\b" + word + "\\b", regex_constants::icase);
    auto wordsBegin = sregex_iterator(line.begin(), line.end(), wordRegex);
    auto wordsEnd = sregex_iterator();
    return distance(wordsBegin, wordsEnd);
}

int main() {
    string filename, wordToCount;

    cout << "Enter the filename: ";
    cin >> filename;
    cout << "Enter the word to count: ";
    cin >> wordToCount;

    ifstream file(filename);
    if (!file.is_open()) {
        cerr << "Error opening file: " << filename << endl;
        return 1;
    }

    string line;
    int totalCount = 0;

    while (getline(file, line)) {
        totalCount += countOccurrencesInLine(line, wordToCount);
    }

    if (file.fail() && !file.eof()) {
        cerr << "Error reading file: " << filename << endl;
        return 1;
    }

    file.close();

    cout << "The word '" << wordToCount << "' occurred " << totalCount << " times in the file " << filename << "." << endl;

    return 0;
}
