from typing import Any, List

class QueueUsingStacks:
    def __init__(self):
        self.stack1: List[Any] = []  # For enqueue operations
        self.stack2: List[Any] = []  # For dequeue operations

    def enqueue(self, item: Any) -> None:
        self.stack1.append(item)

    def dequeue(self) -> Any:
        if not self.stack2:
            if not self.stack1:
                raise IndexError("Queue is empty")
            self._transfer_stack1_to_stack2()
        return self.stack2.pop()

    def peek(self) -> Any:
        if not self.stack2:
            if not self.stack1:
                raise IndexError("Queue is empty")
            self._transfer_stack1_to_stack2()
        return self.stack2[-1]

    def is_empty(self) -> bool:
        return not self.stack1 and not self.stack2

    def size(self) -> int:
        return len(self.stack1) + len(self.stack2)

    def _transfer_stack1_to_stack2(self) -> None:
        while self.stack1:
            self.stack2.append(self.stack1.pop())

    def clear(self) -> None:
        self.stack1.clear()
        self.stack2.clear()

    def __len__(self) -> int:
        return self.size()

    def __repr__(self) -> str:
        return f"QueueUsingStacks({self.stack1}, {self.stack2})"

# Example Usage
if __name__ == "__main__":
    q = QueueUsingStacks()
    q.enqueue(1)
    q.enqueue(2)
    q.enqueue(3)
    print(q.dequeue())  # Output: 1
    print(q.peek())     # Output: 2
    q.enqueue(4)
    print(q.dequeue())  # Output: 2
    print(q.size())     # Output: 2
    print(q.is_empty()) # Output: False
    q.clear()
    print(q.is_empty()) # Output: True
    try:
        q.dequeue()
    except IndexError as e:
        print(str(e))  # Output: Queue is empty
```

1. **Initialization**: Two stacks, `stack1` and `stack2`, manage the queue operations.
2. **Enqueue**: Adds items to `stack1` (O(1)).
3. **Dequeue**: Transfers elements from `stack1` to `stack2` if `stack2` is empty, then pops from `stack2` (amortized O(1)).
4. **Peek**: Similar to `dequeue`, but returns the top element of `stack2` without removing it (amortized O(1)).
5. **Helper Methods**: `_transfer_stack1_to_stack2` transfers elements, `is_empty` checks if both stacks are empty, `size` returns the total number of elements, `clear` empties both stacks, `__len__` allows `len()` usage, and `__repr__` provides a string representation for debugging.
